//! nanopath-embed-server — sovereign pathology tile embedding endpoint for the
//! monster-studio "Microscope" panel. Loads OUR trained DinoV2ViT-B (.knot from
//! packages/nanopath/export_knot.py) and serves the contract submitNanopathEmbedding
//! already speaks:
//!
//!   POST /nanopath-embedding   body = raw image bytes (png/webp/jpeg) [or multipart "tile"]
//!     -> 200 {"embedding": float[DIM], "dim": DIM, "source": "vitb-real", "model": "..."}
//!   GET  /healthz  -> {"ok":true,"dim":DIM}
//!
//! Readout via ?mode=cls (default 768-d) or ?mode=rk_fusion (3072-d, our best).
//! CPU-only, ms-scale per tile; this binary IS the mesh node (Cloud Run, min=0, $0-idle).
//!
//!   cargo run --release --bin nanopath-embed-server -- --knot dinov2-path.knot --port 8088
use std::sync::{Arc, Mutex};

use image::imageops::FilterType;
use tiny_http::{Header, Method, Response, Server};

use distributed_inference::loader::KnotWeights;
use distributed_inference::model_dinov2_vit::{DinoV2ViT, DinoV2VitConfig, Readout};

const MEAN: [f32; 3] = [0.485, 0.456, 0.406];
const STD: [f32; 3] = [0.229, 0.224, 0.225];

fn arg(flag: &str, default: &str) -> String {
    let a: Vec<String> = std::env::args().collect();
    a.iter().position(|x| x == flag).and_then(|i| a.get(i + 1).cloned()).unwrap_or_else(|| default.to_string())
}

/// Locate the start of an image payload, tolerating a multipart/form-data wrapper:
/// scan for a known magic (PNG/JPEG/WEBP) and slice from there (the decoder stops at the
/// image's own end and ignores any trailing multipart boundary). Falls back to the whole body.
fn image_start(b: &[u8]) -> &[u8] {
    let magics: [&[u8]; 3] = [b"\x89PNG\r\n\x1a\n", b"\xff\xd8\xff", b"RIFF"];
    for m in magics {
        if let Some(i) = b.windows(m.len()).position(|w| w == m) {
            // WEBP: RIFF....WEBP — only accept RIFF if "WEBP" follows at +8
            if m == b"RIFF" && !(b.len() >= i + 12 && &b[i + 8..i + 12] == b"WEBP") { continue; }
            return &b[i..];
        }
    }
    b
}

/// Decode arbitrary image bytes -> normalized CHW f32 [3,224,224] (training preprocess).
fn preprocess(bytes: &[u8]) -> Result<Vec<f32>, String> {
    let raw = image_start(bytes);
    let img = image::load_from_memory(raw).map_err(|e| format!("decode: {e}"))?;
    let img = img.resize_exact(224, 224, FilterType::Triangle).to_rgb8();
    let (w, h) = (224usize, 224usize);
    let mut chw = vec![0f32; 3 * h * w];
    for y in 0..h {
        for x in 0..w {
            let p = img.get_pixel(x as u32, y as u32);
            for c in 0..3 {
                chw[c * h * w + y * w + x] = (p[c] as f32 / 255.0 - MEAN[c]) / STD[c];
            }
        }
    }
    Ok(chw)
}

fn cors(resp: Response<std::io::Cursor<Vec<u8>>>) -> Response<std::io::Cursor<Vec<u8>>> {
    resp.with_header(Header::from_bytes(&b"Access-Control-Allow-Origin"[..], &b"*"[..]).unwrap())
        .with_header(Header::from_bytes(&b"Access-Control-Allow-Methods"[..], &b"POST, GET, OPTIONS"[..]).unwrap())
        .with_header(Header::from_bytes(&b"Access-Control-Allow-Headers"[..], &b"*"[..]).unwrap())
}

fn json(code: u16, body: String) -> Response<std::io::Cursor<Vec<u8>>> {
    cors(Response::from_string(body)
        .with_status_code(code)
        .with_header(Header::from_bytes(&b"Content-Type"[..], &b"application/json"[..]).unwrap()))
}

fn main() -> Result<(), String> {
    let knot = arg("--knot", "dinov2-path.knot");
    let port = arg("--port", "8088");
    let model_name = std::path::Path::new(&knot).file_name().and_then(|s| s.to_str()).unwrap_or("dinov2").to_string();

    eprintln!("[nanopath-embed] loading {knot} ...");
    let kw = KnotWeights::load(&knot)?;
    let model = Arc::new(Mutex::new(DinoV2ViT::new(DinoV2VitConfig::default(), kw.backend.clone())?));
    eprintln!("[nanopath-embed] ready on :{port}  (POST /nanopath-embedding)");

    let server = Server::http(format!("0.0.0.0:{port}")).map_err(|e| e.to_string())?;
    for mut req in server.incoming_requests() {
        let url = req.url().to_string();
        let path = url.split('?').next().unwrap_or("").to_string();
        let rk = url.contains("mode=rk_fusion");
        match (req.method(), path.as_str()) {
            (Method::Options, _) => { let _ = req.respond(cors(Response::from_string(""))); }
            (Method::Get, "/healthz") => {
                let dim = if rk { 3072 } else { 768 };
                let _ = req.respond(json(200, format!("{{\"ok\":true,\"dim\":{dim}}}")));
            }
            (Method::Post, "/nanopath-embedding") => {
                let mut body = Vec::new();
                if req.as_reader().read_to_end(&mut body).is_err() {
                    let _ = req.respond(json(400, "{\"error\":\"read body\"}".into())); continue;
                }
                let resp = match preprocess(&body) {
                    Err(e) => json(400, format!("{{\"error\":{:?}}}", e)),
                    Ok(px) => {
                        let readout = if rk { Readout::RkFusion(vec![4, 6, 8, 11]) } else { Readout::Cls };
                        let m = model.lock().unwrap();
                        match m.forward(&px, &readout) {
                            Err(e) => json(500, format!("{{\"error\":{:?}}}", e)),
                            Ok(emb) => {
                                let nums: Vec<String> = emb.iter().map(|v| format!("{v:.6}")).collect();
                                json(200, format!(
                                    "{{\"embedding\":[{}],\"dim\":{},\"source\":\"vitb-real\",\"model\":{:?}}}",
                                    nums.join(","), emb.len(), model_name))
                            }
                        }
                    }
                };
                let _ = req.respond(resp);
            }
            _ => { let _ = req.respond(json(404, "{\"error\":\"not found\"}".into())); }
        }
    }
    Ok(())
}
